#!/usr/bin/env bash
# copy-exactly-td-hvm-fab-fab.sh — 工艺移植 / Copy-Exactly（TD→HVM、fab→fab 量产移交与持续改善） SOP walkthrough for 半导体芯片制造工艺.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="半导体芯片制造工艺"
WORKFLOW="工艺移植 / Copy-Exactly（TD→HVM、fab→fab 量产移交与持续改善）"

usage() {
  cat <<EOF
copy-exactly-td-hvm-fab-fab.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./copy-exactly-td-hvm-fab-fab.sh             # interactive
  ./copy-exactly-td-hvm-fab-fab.sh --dry-run
  ./copy-exactly-td-hvm-fab-fab.sh --json
  ./copy-exactly-td-hvm-fab-fab.sh --explain
  ./copy-exactly-td-hvm-fab-fab.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "工艺移植 / Copy-Exactly（TD→HVM、fab→fab 量产移交与持续改善）" 工作流。

一句话: 从「一个工艺在研发线（TD）或源 fab 跑通」到「在量产 fab / 新 fab 严格复制、参数与良率匹配源线、快速 ramp」。Intel "Copy Exactly!" 是其经典方法学。 (evidence: [T03-S007])

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 物理硬约束 ⇄ 良率/成本经济约束（第一性双重张力）: 半导体工艺的每个决策都同时受两类硬约束——物理/化学/材料（量子隧穿、短沟道效应、RC 延迟、热预算、缺陷物理）与良率/成本经济（D0 缺陷密度、每片晶圆成本、wph、折旧）；摩尔定律首先是**经济命
  • 设备/工艺是必要非充分，良率 know-how 才是真壁垒: 能不能做先进制程，从来不是「有没有 EUV/光刻机」单一决定的——设备 + 材料 + 刻蚀/沉积 + 工艺整合 + 良率爬坡**五要素缺一不可**，而良率 ramp 的 know-how 是 silo

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**锁定基线（everything matters）**：把源线的设备型号/配方/材料/量测/even 看似无关的参数全部记录为基线 —— copy exactly 的前提是先冻结一切。 (evidence: [T03-S007])"
  "**严格复制到目标 fab**：目标 fab 用相同设备型号、相同配方、相同材料、相同操作，不做「本地优化」。 (evidence: [T03-S007])"
  "**参数比对与匹配（matching）**：用相同测试结构跑两线，比对 CD/电性/良率分布，差异处查设备指纹（chamber matching）。"
  "**达匹配后 ramp**：匹配确认后快速放量，because 工艺已锁定。 (evidence: [T03-S007])"
  "**BKM 双向回流**：任一 fab 找到改善（BKM），经评估后同步复制到所有同工艺 fab（虚拟工厂）。 (evidence: [T03-S007])"
)
declare -a FAILURE_MODES=(
  "**目标 fab「本地优化」破坏 matching**：好心改配方引入未知变量，两线对不齐 —— copy-exactly 期严禁本地优化，先一致再统一改。"
  "**只比最终良率不比 chamber 指纹**：matching 差异根因藏在 chamber 级参数，最终良率掩盖了过程漂移 —— 做设备指纹/chamber matching。"
  "**BKM 困在单 fab**：改善不回流，其他 fab 重复踩同一坑、浪费数月 —— 虚拟工厂机制双向复制 BKM。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "copy-exactly-td-hvm-fab-fab-walkthrough"
fi
